using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>().ToContainer("Products");

        // EF Core 9 changed the default discriminator property from "Discriminator" to "$type".
        // Existing 500K documents use "Discriminator", and direct SQL queries reference c.Discriminator.
        modelBuilder.Entity<Product>().HasDiscriminator<string>("Discriminator");

        // EF Core 9 changed id format from "EntityType|KeyValue" to just "KeyValue".
        // Existing documents have ids like "Product|123"; this preserves that format.
        modelBuilder.Entity<Product>().HasRootDiscriminatorInJsonId(true);

        // HasIndex was removed — Cosmos DB indexing is managed via the container's indexing policy,
        // not through EF Core. The previous call was silently ignored; EF Core 9 now throws.
    }
}
class Product { public int Id { get; set; } public string Sku { get; set; } }

